const getCKScoreHistory = `-- name: GetCKScoreHistory :many
SELECT
    TO_CHAR(recorded_at AT TIME ZONE 'UTC', 'YYYY-MM-DD')::text AS date,
    MAX(score)::float8                                         AS score,
    MAX(controls_total)::int                                   AS controls_total,
    MAX(controls_implemented)::int                             AS controls_implemented
FROM ck_score_history
WHERE org_id = $1
  AND framework_id IS NULL
  AND recorded_at >= NOW() - ($2::int || ' days')::INTERVAL
GROUP BY date
ORDER BY date ASC
`

type GetCKScoreHistoryParams struct {
	OrgID string `json:"org_id"`
	Days  int32  `json:"days"`
}

type GetCKScoreHistoryRow struct {
	Date                string  `json:"date"`
	Score               float64 `json:"score"`
	ControlsTotal       int32   `json:"controls_total"`
	ControlsImplemented int32   `json:"controls_implemented"`
}

// Aggregiert pro Tag (TO_CHAR auf UTC); MAX statt LAST/FIRST_VALUE weil
// mehrere Snapshots am gleichen Tag normaler Fall sind. Score wird in
// float8 gecastet damit sqlc keinen any-Typ generiert.
func (q *Queries) GetCKScoreHistory(ctx context.Context, arg GetCKScoreHistoryParams) ([]GetCKScoreHistoryRow, error) {
	rows, err := q.db.Query(ctx, getCKScoreHistory, arg.OrgID, arg.Days)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	items := []GetCKScoreHistoryRow{}
	for rows.Next() {
		var i GetCKScoreHistoryRow
		if err := rows.Scan(
			&i.Date,
			&i.Score,
			&i.ControlsTotal,
			&i.ControlsImplemented,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

