// den verschiedenen Aggregaten, die der secvitals-Service benötigt
// (Sector-Settings, Admin-Mailings, Cross-Org-Seeding).
func (q *Queries) ListAllOrgIDs(ctx context.Context) ([]string, error) {
	rows, err := q.db.Query(ctx, listAllOrgIDs)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	items := []string{}
	for rows.Next() {
		var id string
		if err := rows.Scan(&id); err != nil {
			return nil, err
		}
		items = append(items, id)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

