const updateCKCAPA = `-- name: UpdateCKCAPA :one
UPDATE ck_capas SET
  title             = COALESCE($3::text, title),
  description       = COALESCE($4::text, description),
  root_cause        = COALESCE($5::text, root_cause),
  action_plan       = COALESCE($6::text, action_plan),
  assignee_email    = COALESCE($7::text, assignee_email),
  due_date          = COALESCE($8::date, due_date),
  priority          = COALESCE($9::text, priority),
  status            = COALESCE($10::text, status),
  verification_note = COALESCE($11::text, verification_note),
  closed_at         = CASE
                       WHEN $10::text = 'closed' AND closed_at IS NULL THEN NOW()
                       ELSE closed_at
                      END,
  updated_at        = NOW()
WHERE id = $1 AND org_id = $2
RETURNING id, org_id, source_type, source_id, title, description,
          root_cause, action_plan, assignee_email, due_date, priority,
          status, verification_note, closed_at, created_at, updated_at
`

type UpdateCKCAPAParams struct {
	ID               string      `json:"id"`
	OrgID            string      `json:"org_id"`
	Title            pgtype.Text `json:"title"`
	Description      pgtype.Text `json:"description"`
	RootCause        pgtype.Text `json:"root_cause"`
	ActionPlan       pgtype.Text `json:"action_plan"`
	AssigneeEmail    pgtype.Text `json:"assignee_email"`
	DueDate          pgtype.Date `json:"due_date"`
	Priority         pgtype.Text `json:"priority"`
	Status           pgtype.Text `json:"status"`
	VerificationNote pgtype.Text `json:"verification_note"`
}

// COALESCE-Pattern: nil-narg → behalten. Spezialregel für closed_at:
// Bei Übergang in Status 'closed' wird closed_at = NOW() gesetzt — aber
// nur wenn vorher noch NULL. Wechselt der Status zurück, bleibt closed_at
// erhalten (audit-trail-Spalte).
func (q *Queries) UpdateCKCAPA(ctx context.Context, arg UpdateCKCAPAParams) (CkCapas, error) {
	row := q.db.QueryRow(ctx, updateCKCAPA,
		arg.ID,
		arg.OrgID,
		arg.Title,
		arg.Description,
		arg.RootCause,
		arg.ActionPlan,
		arg.AssigneeEmail,
		arg.DueDate,
		arg.Priority,
		arg.Status,
		arg.VerificationNote,
	)
	var i CkCapas
	err := row.Scan(
		&i.ID,
		&i.OrgID,
		&i.SourceType,
		&i.SourceID,
		&i.Title,
		&i.Description,
		&i.RootCause,
		&i.ActionPlan,
		&i.AssigneeEmail,
		&i.DueDate,
		&i.Priority,
		&i.Status,
		&i.VerificationNote,
		&i.ClosedAt,
		&i.CreatedAt,
		&i.UpdatedAt,
	)
	return i, err
}

